template <typename T, LLI BASE, LLI MOD> class RollingHash{

private:

  static vector<LLI> pow;



public:

  static void init(int N){

    pow.assign(N+1,0);

    pow[0] = 1;

    FORE(i,1,N){

      pow[i] = pow[i-1]*BASE % MOD;

    }

  }



  static vector<LLI> generate_hash(const T &s){

    vector<LLI> ret(s.size()+1);



    FORE(i,1,(int)s.size()){

      ret[i] = (ret[i-1]*BASE+s[i-1]) % MOD;

    }



    return ret;

  }



  static LLI hash(const vector<LLI> &shash, int i, int j){ // [i, j)

    return (shash[j] - shash[i] * pow[j-i] + MOD*MOD) % MOD;

  }



  static LLI hash(const T &p){

    LLI phash = 0;

    REP(i,(int)p.size()) phash = (phash*BASE+p[i]) % MOD;

    return phash;

  }





  static vector<int> find(const vector<LLI> &shash, const T &p){

    vector<int> ret;

    int pl = p.size();

    LLI phash = hash(p);

    REP(i,(int)shash.size()-pl) if(hash(shash,i,i+pl) == phash) ret.push_back(i);

    return ret;

