  R2::init(10000);



  int N;

  string s;

  while(cin >> N >> s){



    auto hs1 = R1::generate_hash(s);

    auto hs2 = R2::generate_hash(s);



    int ans = 0;



    auto check =

      [&](int L){

        set<pair<LLI,LLI>> store;

        queue<pair<LLI,LLI>> q;



        REP(i,N-L+1){

          auto h1 = R1::hash(hs1,i,i+L);

          auto h2 = R2::hash(hs2,i,i+L);



          pair<LLI,LLI> H(h1,h2);



          if(EXIST(store,H)){

            return true;

          }



          if((int)q.size() == L-1){

            q.push(H);

            auto t = q.front(); q.pop();

            store.insert(t);

          }else{

            q.push(H);

          }

        }



        return false;

      };



    int lb = 0, ub = N, mid;

    while(abs(lb-ub) > 1){

      mid = (lb+ub)/2;



      if(check(mid)){

        lb = mid;

      }else{

        ub = mid;

      }

    }



    ans = lb;



    cout << ans << endl;

  }





  return 0;

}

