const int MAXN = 5050;



const long long P1 = 1087;

const long long P2 = 1097;

const long long MOD1 = 1e9 + 7;

const long long MOD2 = 1e9 + 123;





int N;



char ar[MAXN];



long long int hash1[MAXN];

long long int hash2[MAXN];



long long int power1[MAXN];

long long int power2[MAXN];



inline long long get_hash( int i, int len, long long P, long long MOD, long long power[], long long hash[] ) {



	long long first = (hash[i] - hash[i + len] + MOD) % MOD;



	return (first * power[i]) % MOD;

}



inline bool check( int len ) {



	for( int i=1 ; i <= N ; i++ ) {

		for( int j = i + len ; j <= N - len + 1 ; j++ ) {

			if ( get_hash(i, len, P1, MOD1, power1, hash1) == get_hash(j, len, P1, MOD1, power1, hash1)

			 && get_hash(i, len, P2, MOD2, power2, hash2) == get_hash(j, len, P2, MOD2, power2, hash2) ) {

				// cerr << i << " " << j << " " << len << endl;

				return true;

			}

		}

	}



	return false;

}



int main() {



	string s;



	power1[0] = power2[0] = 1LL;



	for( int i=1 ; i < MAXN ; i++ ) {

		power1[i] = (power1[i - 1] * P1) % MOD1;

		power2[i] = (power2[i - 1] * P2) % MOD2;

	}



	scanf("%d%s", &N, ar + 1);



	for( int i=N ; i ; i-- ) {

		hash1[i] = (((power1[N - i] * (ar[i] - 'a')) % MOD1) + hash1[i + 1]) % MOD1;

		hash2[i] = (((power2[N - i] * (ar[i] - 'a')) % MOD2) + hash2[i + 1]) % MOD2;

	}



	int lo = 0, hi = N, result;



	cerr << hi << endl;



	while( lo <= hi ) {



		int mi = (lo + hi) / 2;



		// cerr << mi << endl;



		if (check(mi)) {

			result = mi;

			lo = mi + 1;

		} else {

			hi = mi - 1;

		}

	}



	printf("%d\n", result);

	return 0;

}

