	for( int i=1 ; i <= N ; i++ ) {

		for( int j = i + len ; j <= N - len + 1 ; j++ ) {

			if ( get_hash(i, len, P1, MOD1, power1, hash1) == get_hash(j, len, P1, MOD1, power1, hash1)

